import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import axios, { AxiosError, AxiosInstance } from 'axios';
import { createHmac } from 'crypto';

import {
  NOWPaymentsCreatePayoutRequest,
  NOWPaymentsCreatePayoutResponse,
  NOWPaymentsCurrenciesResponse,
  NOWPaymentsErrorResponse,
  NOWPaymentsPaymentResponse,
  NOWPaymentsPayoutResponse,
} from '../types/nowpayments.types';

/**
 * NOWPayments Payment Status
 */
export enum NOWPaymentStatus {
  Waiting = 'waiting',
  Confirming = 'confirming',
  Confirmed = 'confirmed',
  Processing = 'processing',
  Finished = 'finished',
  Failed = 'failed',
  Expired = 'expired',
}

/**
 * NOWPayments API Request Types
 */
export interface CreatePaymentRequest {
  price_amount: number;
  price_currency: string;
  pay_currency?: string;
  ipn_callback_url: string;
  order_id?: string;
  order_description?: string;
  success_url?: string;
  cancel_url?: string;
  is_fixed_rate?: boolean;
  is_fee_paid_by_user?: boolean;
}

// Use types from types file
export type PaymentResponse = NOWPaymentsPaymentResponse;
export type PayoutRequest = NOWPaymentsCreatePayoutRequest;
export type PayoutCreateResponse = NOWPaymentsCreatePayoutResponse;
export type PayoutResponse = NOWPaymentsPayoutResponse;

/**
 * NOWPaymentsService
 *
 * Thin wrapper around NOWPayments API.
 * Responsible for:
 * - Initializing API client with API key
 * - Creating payments
 * - Retrieving payment status
 * - Creating payouts (withdrawals)
 *
 * High-level business flows should be implemented in separate services.
 */
@Injectable()
export class NOWPaymentsService {
  private readonly logger = new Logger(NOWPaymentsService.name);
  private axiosInstance: AxiosInstance;
  private apiKey: string;
  private payoutToken?: string;
  private payoutTokenExpiresAt?: number;
  private payoutAuthEmail: string;
  private payoutAuthPassword: string;
  private ipnSecret: string;
  private baseUrl: string;

  constructor(private readonly configService: ConfigService) {
    this.apiKey = this.getRequiredConfigValue('NOWPAYMENTS_API_KEY');
    this.payoutAuthEmail = this.getRequiredConfigValue(
      'NOWPAYMENTS_AUTH_EMAIL',
    );
    this.payoutAuthPassword = this.getRequiredConfigValue(
      'NOWPAYMENTS_AUTH_PASSWORD',
    );
    this.ipnSecret = this.getRequiredConfigValue('NOWPAYMENTS_IPN_SECRET');
    this.baseUrl = this.configService.getOrThrow<string>(
      'NOWPAYMENTS_BASE_URL',
    );

    // Initialize axios instance with API key in headers
    this.axiosInstance = axios.create({
      baseURL: this.baseUrl,
      headers: {
        'x-api-key': this.apiKey,
        'Content-Type': 'application/json',
      },
    });

    this.logger.log(`NOWPayments service initialized`);
  }

  private getRequiredConfigValue(key: string): string {
    const value = this.configService.getOrThrow<string>(key);

    if (!value) {
      throw new Error(`Missing NOWPayments configuration: ${key}`);
    }

    return value;
  }

  private isPayoutTokenValid(): boolean {
    if (!this.payoutToken) {
      return false;
    }

    if (!this.payoutTokenExpiresAt) {
      return true;
    }

    const now = Date.now();
    return now + 5_000 < this.payoutTokenExpiresAt;
  }

  private parseExpiry(raw: unknown): number | undefined {
    if (typeof raw === 'number') {
      // Assume seconds if it's too small to be ms
      return raw < 1e12 ? raw * 1000 : raw;
    }

    if (typeof raw === 'string') {
      const parsed = Date.parse(raw);
      if (!Number.isNaN(parsed)) {
        return parsed;
      }
    }

    return undefined;
  }

  private async getPayoutAuthToken(): Promise<string> {
    if (this.isPayoutTokenValid()) {
      return this.payoutToken as string;
    }

    const response = await this.axiosInstance.post<{
      token?: string;
      access_token?: string;
      auth_token?: string;
      expires_at?: string | number;
      expire_at?: string | number;
      expiration?: string | number;
      expired_at?: string | number;
    }>('/auth', {
      email: this.payoutAuthEmail,
      password: this.payoutAuthPassword,
    });

    if (response.status !== 200) {
      throw new Error(
        `Failed to authorize NOWPayments payout: ${response.status}`,
      );
    }

    const data = response.data || {};
    const token = data.token || data.access_token || data.auth_token;
    if (!token) {
      throw new Error(
        `NOWPayments payout auth failed: missing token in response`,
      );
    }

    const expiry =
      this.parseExpiry(data.expires_at) ||
      this.parseExpiry(data.expire_at) ||
      this.parseExpiry(data.expiration) ||
      this.parseExpiry(data.expired_at) ||
      Date.now() + 4 * 60 * 1000;

    this.payoutToken = token;
    this.payoutTokenExpiresAt = expiry;

    return token;
  }

  /**
   * Create a payment with NOWPayments
   * @param request Payment request parameters
   * @returns Payment response with payment ID and details
   */
  async createPayment(request: CreatePaymentRequest): Promise<PaymentResponse> {
    try {
      this.logger.log(
        `Sending request to NOWPayments: ${JSON.stringify(request)}`,
      );

      const response = await this.axiosInstance.post<PaymentResponse>(
        '/payment',
        request,
      );

      if (response.status !== 201 && response.status !== 200) {
        throw new Error(
          `Failed to create NOWPayments payment: ${response.status}`,
        );
      }

      const payment = response.data;

      this.logger.log(`Created NOWPayments payment: ${payment.payment_id}`);

      return payment;
    } catch (error) {
      // Type guard for Axios errors
      if (axios.isAxiosError(error)) {
        const axiosError = error as AxiosError<NOWPaymentsErrorResponse>;

        // Log response data if available
        if (axiosError.response?.data) {
          this.logger.error(
            `NOWPayments API error response: ${JSON.stringify(axiosError.response.data)}`,
          );
          this.logger.error(
            `Request that caused error: ${JSON.stringify(request)}`,
          );
        }

        // Handle rate limiting
        if (axiosError.response?.status === 429) {
          throw new Error(
            'NOWPayments rate limit exceeded. Please try again in a minute.',
          );
        }

        const errorMessage =
          axiosError.response?.data?.message ||
          axiosError.message ||
          'Unknown error';
        throw new Error(`NOWPayments payment creation failed: ${errorMessage}`);
      }

      // Non-Axios error
      this.logger.error('Failed to create NOWPayments payment', error);
      const errorMessage =
        error instanceof Error ? error.message : String(error);
      throw new Error(`NOWPayments payment creation failed: ${errorMessage}`);
    }
  }

  /**
   * Get payment status by ID
   * @param paymentId NOWPayments payment ID
   * @returns Payment details with current status
   */
  async getPayment(paymentId: number): Promise<PaymentResponse> {
    try {
      const response = await this.axiosInstance.get<PaymentResponse>(
        `/payment/${paymentId}`,
      );

      if (response.status !== 200) {
        throw new Error(
          `Failed to get NOWPayments payment: ${response.status}`,
        );
      }

      return response.data;
    } catch (error) {
      this.logger.error(
        `Failed to get NOWPayments payment: ${paymentId}`,
        error,
      );
      throw new Error(
        `NOWPayments payment retrieval failed: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  }

  /**
   * Create a payout (withdrawal)
   * @param request Payout request parameters
   * @returns Payout response with payout ID
   */
  async createPayout(request: PayoutRequest): Promise<PayoutCreateResponse> {
    try {
      const payoutToken = await this.getPayoutAuthToken();
      const response = await this.axiosInstance.post<PayoutCreateResponse>(
        '/payout',
        request,
        {
          headers: {
            Authorization: `Bearer ${payoutToken}`,
          },
        },
      );

      if (response.status !== 201 && response.status !== 200) {
        throw new Error(
          `Failed to create NOWPayments payout: ${response.status}`,
        );
      }

      const payout = response.data;

      this.logger.log(`Created NOWPayments payout: ${payout.id}`);

      return payout;
    } catch (error) {
      this.logger.error('Failed to create NOWPayments payout', error);
      throw new Error(
        `NOWPayments payout creation failed: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  }

  /**
   * Get payout status by ID
   * @param payoutId NOWPayments payout ID
   * @returns Payout details with current status
   */
  async getPayout(payoutId: number): Promise<PayoutResponse> {
    try {
      const response = await this.axiosInstance.get<PayoutResponse>(
        `/payout/${payoutId}`,
      );

      if (response.status !== 200) {
        throw new Error(`Failed to get NOWPayments payout: ${response.status}`);
      }

      return response.data;
    } catch (error) {
      this.logger.error(`Failed to get NOWPayments payout: ${payoutId}`, error);
      throw new Error(
        `NOWPayments payout retrieval failed: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  }

  /**
   * Get list of available currencies
   * @returns Array of currency codes
   */
  async getCurrencies(): Promise<string[]> {
    try {
      const response =
        await this.axiosInstance.get<NOWPaymentsCurrenciesResponse>(
          '/currencies',
        );

      if (response.status !== 200) {
        throw new Error(
          `Failed to get NOWPayments currencies: ${response.status}`,
        );
      }

      this.logger.log(
        `Retrieved ${response.data.currencies.length} currencies from NOWPayments`,
      );

      return response.data.currencies;
    } catch (error) {
      this.logger.error('Failed to get NOWPayments currencies', error);
      throw new Error(
        `NOWPayments currencies retrieval failed: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
  }

  /**
   * Verify IPN signature from webhook
   * @param data Raw webhook payload
   * @param signature Signature from header
   * @returns true if signature is valid
   */
  verifyIPNSignature(
    payload: Record<string, unknown>,
    signature: string,
  ): boolean {
    try {
      // Функция для сортировки и сериализации объекта
      const sortObject = (obj: any): any => {
        if (obj === null || obj === undefined) {
          return obj;
        }

        if (Array.isArray(obj)) {
          return obj.map(sortObject);
        }

        if (typeof obj === 'object') {
          return Object.keys(obj)
            .sort()
            .reduce((result: any, key: string) => {
              result[key] = sortObject(obj[key]);
              return result;
            }, {});
        }

        return obj;
      };

      // Сортируем объект
      const sortedPayload = sortObject(payload);

      // Конвертируем в JSON строку (NOWPayments использует JSON, не query string)
      const payloadString = JSON.stringify(sortedPayload);

      this.logger.debug(`IPN Signature verification:
      Payload string: ${payloadString}
      Expected: ${signature}`);

      // Вычисляем HMAC
      const computedSignature = createHmac('sha512', this.ipnSecret)
        .update(payloadString)
        .digest('hex');

      this.logger.debug(`Computed: ${computedSignature}
      Match: ${computedSignature === signature}`);

      return computedSignature === signature;
    } catch (error) {
      this.logger.error('Error verifying IPN signature:', error);
      return false;
    }
  }
}

